package main

import (
	"fmt"
	"net/http"
	"io/ioutil"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusBadRequest)
		return
	}

	// Print the request content
	fmt.Printf("Request Content: %s\n", body)

	// Close the request body to avoid leaving it open
	r.Body.Close()

	// Send a response back to the client
	w.Write([]byte("Request content received"))
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}
```

This code sets up a simple HTTP server that listens on port 8080. When a request is received, it reads the request body and prints it to the console. Note that the request body is closed after reading to avoid resource leaks.

